/// trap), so a rogue byte cannot crash the parser.
public enum FlashIcType: UInt8, CaseIterable {
    /// generic SPI-flash deep-sleep command flow
    case auto = 0
}

// MARK: - Bitfield groups

/// SystemConfig.communication_modes @bits CommunicationModes (bits 3-7 reserved).
public struct CommunicationModes: OptionSet {
    public let rawValue: UInt8
    public init(rawValue: UInt8) { self.rawValue = rawValue }

    /// BLE transfer supported
    public static let ble = CommunicationModes(rawValue: 1 << 0)
    /// OEPL (OpenEPaperLink) transfer supported
    public static let oepl = CommunicationModes(rawValue: 1 << 1)
    /// WiFi transfer supported
    public static let wifi = CommunicationModes(rawValue: 1 << 2)
}

/// SystemConfig.device_flags @bits DeviceFlags (bits 5-7 reserved).
public struct DeviceFlags: OptionSet {
    public let rawValue: UInt8
    public init(rawValue: UInt8) { self.rawValue = rawValue }

    /// device has external power management for the display etc.
    public static let pwrPin = DeviceFlags(rawValue: 1 << 0)
    /// apply Seeed XIAO low-power init
    public static let xiaoInit = DeviceFlags(rawValue: 1 << 1)
    /// apply Waveshare PhotoPainter low-power init
    public static let wsPpInit = DeviceFlags(rawValue: 1 << 2)
    /// self-holding MOSFET latch on pwr_pin_2; optional long-press shutdown button on
    /// pwr_pin_3
    public static let pwrLatch = DeviceFlags(rawValue: 1 << 3)
    /// 74AHC1G79 D-FF latch: pwr_pin_2=D (hold), pwr_pin_3=CP (clock); command 0x0052
    /// releases latch
    public static let pwrLatchDff = DeviceFlags(rawValue: 1 << 4)
}

/// PowerOption.sleep_flags @bits SleepFlags (bits 1-7 reserved). Firmware ships bit0;
/// config.yaml still lists it reserved_0 (yaml is behind).
public struct SleepFlags: OptionSet {
    public let rawValue: UInt8
    public init(rawValue: UInt8) { self.rawValue = rawValue }

    /// opt out of button wake from timer deep sleep (buttons sharing wake-hostile pads)
    public static let disable = SleepFlags(rawValue: 1 << 0)
}

/// PowerOption.battery_sense_flags @bits BatterySenseFlags (bits 1-7 reserved). Firmware
/// ships bit0; config.yaml still lists it reserved_0 (yaml is behind).
public struct BatterySenseFlags: OptionSet {
    public let rawValue: UInt8
    public init(rawValue: UInt8) { self.rawValue = rawValue }

    /// battery-sense enable is active-low (e.g. XIAO ~READ_BAT on P0.14)
    public static let inverted = BatterySenseFlags(rawValue: 1 << 0)
}

/// PowerOption.charger_flags @bits ChargerFlags (bits 2-7 reserved).
public struct ChargerFlags: OptionSet {
    public let rawValue: UInt8
    public init(rawValue: UInt8) { self.rawValue = rawValue }

    /// charge-enable (/CE) is active-low
    public static let enableActiveLow = ChargerFlags(rawValue: 1 << 0)
    /// charge-state (BQ25616 STAT) is active-low: charging when LOW
    public static let stateActiveLow = ChargerFlags(rawValue: 1 << 1)
}

/// DisplayConfig.transmission_modes @bits TransmissionModes (bits 5-6 reserved -- named as
/// placeholders below; bit7 is defined above the gap).
public struct TransmissionModes: OptionSet {
    public let rawValue: UInt8
    public init(rawValue: UInt8) { self.rawValue = rawValue }

    /// streaming zlib inflate, 512-byte DEFLATE window (requires zip). Canonical name
    /// resolves the Firmware/Silabs ZIPXL vs NRF54/yaml streaming_decompression split.
    public static let streamingDecompression = TransmissionModes(rawValue: 1 << 0)
    /// zip-compressed transfer (full window)
    public static let zip = TransmissionModes(rawValue: 1 << 1)
    /// Group 5 compression (not yet implemented)
    public static let g5 = TransmissionModes(rawValue: 1 << 2)
    /// direct-write mode (bufferless)
    public static let directWrite = TransmissionModes(rawValue: 1 << 3)
    /// PIPE-write mode: faster transfer via sliding-window pipeline
    public static let pipeWrite = TransmissionModes(rawValue: 1 << 4)
    /// reserved; must be 0 (placeholder name for a future transmission mode)
    public static let reserved5 = TransmissionModes(rawValue: 1 << 5)
    /// reserved; must be 0 (placeholder name for a future transmission mode)
    public static let reserved6 = TransmissionModes(rawValue: 1 << 6)
    /// Clear screen on boot. Synonymous with config.yaml's no_boot_text / NO_BOOT_TEXT --
    /// same bit, same behavior (clearing on boot is why no boot text shows).
    public static let clearOnBoot = TransmissionModes(rawValue: 1 << 7)
}

