    public static let led1Invert = LedFlags(rawValue: 1 << 0)
    /// invert LED channel 2 polarity
    public static let led2Invert = LedFlags(rawValue: 1 << 1)
    /// invert LED channel 3 polarity
    public static let led3Invert = LedFlags(rawValue: 1 << 2)
    /// invert LED channel 4 polarity
    public static let led4Invert = LedFlags(rawValue: 1 << 3)
}

/// Bitfield group BusFlags: DataBus.bus_flags @bits BusFlags -- all bits reserved today
