    public let rawValue: UInt8
    public init(rawValue: UInt8) { self.rawValue = rawValue }

    /// allow unauthenticated config writes while encryption is enabled
    public static let rewriteAllowed = SecurityFlags(rawValue: 1 << 0)
    /// show the encryption key on screen (future feature)
    public static let showKeyOnScreen = SecurityFlags(rawValue: 1 << 1)
    /// reset pin enabled (must be set for the reset pin to work)
    public static let resetPinEnabled = SecurityFlags(rawValue: 1 << 2)
    /// reset-pin polarity: 0 = LOW triggers, 1 = HIGH triggers
    public static let resetPinPolarity = SecurityFlags(rawValue: 1 << 3)
    /// enable pull-up on the reset pin
    public static let resetPinPullup = SecurityFlags(rawValue: 1 << 4)
    /// enable pull-down on the reset pin
    public static let resetPinPulldown = SecurityFlags(rawValue: 1 << 5)
}

