/// MsdAdvertisement.status @bits MsdStatusBits. bit0 is the 9th (MSB) bit of the 10-bit
/// battery voltage; bits 4-7 are a free-running main-loop nibble counter.
public struct MsdStatusBits: OptionSet {
    public let rawValue: UInt8
    public init(rawValue: UInt8) { self.rawValue = rawValue }

    /// high bit of the 10-bit battery voltage (units of 10 mV); combine with
    /// battery_voltage_low
    public static let batteryVoltageBit8 = MsdStatusBits(rawValue: 1 << 0)
    /// device rebooted since last read
    public static let rebootFlag = MsdStatusBits(rawValue: 1 << 1)
    /// device is requesting a connection
    public static let connectionRequested = MsdStatusBits(rawValue: 1 << 2)
    /// reserved; must be 0 (placeholder name for a future status flag; sits between the
    /// flags and the bits 4-7 counter)
    public static let reserved3 = MsdStatusBits(rawValue: 1 << 3)
    /// bits 4-7: free-running main-loop nibble counter (liveness)
    public static let mainLoopCounterShift: UInt8 = 4
    /// mask for the bits 4-7 main-loop counter nibble
    public static let mainLoopCounterMask: UInt8 = 0xF0
}

// MARK: - Cross-header bindings (defined in opendisplay_protocol.h)
/// @enum OD_NFC_IC_*: OD_NFC_IC_AUTO=0, OD_NFC_IC_TNB132M=1
/// @bits PIPE_FLAG_*: PIPE_FLAG_COMPRESSED=1, PIPE_FLAG_PARTIAL=2

// MARK: - Packed structs

/// Wraps the whole transfer: a length+version header, then a sequence of single_packet
/// entries, then a trailing CRC (NOT part of this struct -- it is the last 2 bytes of the
/// outer packet). FOLLOWUP: `length` is populated inconsistently (the website toolbox
/// patches it to the real total incl. CRC; some encoders leave it a zero pad -> [00
/// 00][version]...). The CRC is always computed as if `length` were 0x0000. Verify whether
/// any receiver relies on `length` before firmware depends on it.  [config packet outer]
/// (3 wire bytes.)
public struct OuterPacketHeader: ODPackedStruct {
    public static let wireSize = 3

    /// total outer-packet length INCLUDING the trailing CRC. Inconsistently populated --
    /// may be a real total or a zero pad; the CRC is computed as if this were 0x0000 either
    /// way.
    public var length: UInt16
    /// config-format MAJOR version = OD_CONFIG_VERSION (1). The minor is not carried in the
    /// header.  [enum OD_CONFIG_VERSION]
    public var version: UInt8

    public init(length: UInt16 = 0, version: UInt8 = 0) {
        self.length = length
        self.version = version
    }

    public init?(bytes: [UInt8]) {
        guard bytes.count >= Self.wireSize else { return nil }
        self.length = odReadUInt16(bytes, 0, bigEndian: false)
        self.version = bytes[2]
    }

    public func serialize() -> [UInt8] {
        var out = [UInt8]()
        out.reserveCapacity(Self.wireSize)
        odAppendUInt16(length, &out, bigEndian: false)
        out.append(version)
        return out
    }
}

/// Header preceding each config payload inside the outer packet. The payload that follows
/// is a fixed-size struct whose size and layout are determined entirely by `id` (see
/// ConfigPacketType); there is no per-packet length field -- sizeof the selected struct IS
/// the payload length.  [config packet single]  (2 wire bytes.)
public struct SinglePacketHeader: ODPackedStruct {
    public static let wireSize = 2

    /// 0-based sequential packet index within the outer packet.
    public var number: UInt8
    /// packet-type id selecting the payload struct.  [enum ConfigPacketType]
    public var id: UInt8

    public init(number: UInt8 = 0, id: UInt8 = 0) {
        self.number = number
        self.id = id
    }

    public init?(bytes: [UInt8]) {
        guard bytes.count >= Self.wireSize else { return nil }
        self.number = bytes[0]
        self.id = bytes[1]
    }

    public func serialize() -> [UInt8] {
        var out = [UInt8]()
        out.reserveCapacity(Self.wireSize)
        out.append(number)
        out.append(id)
        return out
    }
}

/// Host IC identity, communication capabilities, and power-management pins. Required
/// singleton. 22 bytes.  [config packet 0x01; required]  (22 wire bytes.)
public struct SystemConfig: ODPackedStruct {
    public static let wireSize = 22
    public static let packetID: UInt8 = 0x01

    /// host MCU/IC of this device.  [enum ICType]
    public var icType: UInt16
    /// supported transfer modes (bitfield).  [bits CommunicationModes]
    public var communicationModes: UInt8
    /// misc device / power-latch flags (bitfield).  [bits DeviceFlags]
    public var deviceFlags: UInt8
    /// primary power-management pin; 0xFF = not present.  [default 0xFF]
    public var pwrPin: UInt8
    /// future use; must be 0.  [reserved]
    public var reserved: [UInt8]
    /// aux enable / battery-latch hold / pwr_latch_dff D input; 0 or 0xFF = firmware
    /// default.
    public var pwrPin2: UInt8
    /// aux enable / battery-latch shutdown button / pwr_latch_dff CP clock; 0 or 0xFF =
    /// none/default.
    public var pwrPin3: UInt8

    public init(icType: UInt16 = 0, communicationModes: UInt8 = 0, deviceFlags: UInt8 = 0, pwrPin: UInt8 = 0, reserved: [UInt8] = [], pwrPin2: UInt8 = 0, pwrPin3: UInt8 = 0) {
        self.icType = icType
        self.communicationModes = communicationModes
        self.deviceFlags = deviceFlags
        self.pwrPin = pwrPin
        self.reserved = reserved
        self.pwrPin2 = pwrPin2
        self.pwrPin3 = pwrPin3
    }

    public init?(bytes: [UInt8]) {
        guard bytes.count >= Self.wireSize else { return nil }
        self.icType = odReadUInt16(bytes, 0, bigEndian: false)
        self.communicationModes = bytes[2]
        self.deviceFlags = bytes[3]
        self.pwrPin = bytes[4]
        self.reserved = Array(bytes[5..<20])
        self.pwrPin2 = bytes[20]
        self.pwrPin3 = bytes[21]
    }

    public func serialize() -> [UInt8] {
        var out = [UInt8]()
        out.reserveCapacity(Self.wireSize)
        odAppendUInt16(icType, &out, bigEndian: false)
        out.append(communicationModes)
        out.append(deviceFlags)
        out.append(pwrPin)
        out.append(contentsOf: odFixedBytes(reserved, 15))
        out.append(pwrPin2)
        out.append(pwrPin3)
        return out
    }
}

/// Manufacturer id, board identity, and the 'simple config' preset indices the website UI
/// applied. Required singleton. 22 bytes.  [config packet 0x02; required]  (22 wire bytes.)
public struct ManufacturerData: ODPackedStruct {
    public static let wireSize = 22
    public static let packetID: UInt8 = 0x02

    /// device manufacturer.  [enum ManufacturerId]
    public var manufacturerId: UInt16
    /// board identifier; meaning depends on manufacturer_id. Value table lives in
    /// config.yaml only (NOT enumerated here) -- raw u8.
    public var boardType: UInt8
    /// board revision number.
    public var boardRevision: UInt8
    /// simple-config driver preset index (1-based; 0 = not set).
    public var simpleConfigDriverIndex: UInt16
    /// simple-config display preset index (1-based; 0 = not set).
    public var simpleConfigDisplayIndex: UInt16
    /// simple-config power preset index (1-based; 0 = not set).
    public var simpleConfigPowerIndex: UInt16
    /// 48-bit little-endian Unix time (seconds) when simple config was last applied.  [unit
    /// s]
    public var simpleConfigConfiguredAt: [UInt8]
    /// future use; must be 0.  [reserved]
    public var reserved: [UInt8]

    public init(manufacturerId: UInt16 = 0, boardType: UInt8 = 0, boardRevision: UInt8 = 0, simpleConfigDriverIndex: UInt16 = 0, simpleConfigDisplayIndex: UInt16 = 0, simpleConfigPowerIndex: UInt16 = 0, simpleConfigConfiguredAt: [UInt8] = [], reserved: [UInt8] = []) {
        self.manufacturerId = manufacturerId
        self.boardType = boardType
        self.boardRevision = boardRevision
        self.simpleConfigDriverIndex = simpleConfigDriverIndex
        self.simpleConfigDisplayIndex = simpleConfigDisplayIndex
        self.simpleConfigPowerIndex = simpleConfigPowerIndex
        self.simpleConfigConfiguredAt = simpleConfigConfiguredAt
        self.reserved = reserved
    }

    public init?(bytes: [UInt8]) {
        guard bytes.count >= Self.wireSize else { return nil }
        self.manufacturerId = odReadUInt16(bytes, 0, bigEndian: false)
        self.boardType = bytes[2]
        self.boardRevision = bytes[3]
        self.simpleConfigDriverIndex = odReadUInt16(bytes, 4, bigEndian: false)
        self.simpleConfigDisplayIndex = odReadUInt16(bytes, 6, bigEndian: false)
        self.simpleConfigPowerIndex = odReadUInt16(bytes, 8, bigEndian: false)
        self.simpleConfigConfiguredAt = Array(bytes[10..<16])
        self.reserved = Array(bytes[16..<22])
    }

    public func serialize() -> [UInt8] {
        var out = [UInt8]()
        out.reserveCapacity(Self.wireSize)
        odAppendUInt16(manufacturerId, &out, bigEndian: false)
        out.append(boardType)
        out.append(boardRevision)
        odAppendUInt16(simpleConfigDriverIndex, &out, bigEndian: false)
        odAppendUInt16(simpleConfigDisplayIndex, &out, bigEndian: false)
        odAppendUInt16(simpleConfigPowerIndex, &out, bigEndian: false)
        out.append(contentsOf: odFixedBytes(simpleConfigConfiguredAt, 6))
        out.append(contentsOf: odFixedBytes(reserved, 6))
        return out
    }
}

/// Power source, battery model, sleep/advertising timing, battery-sense and charger pins,
/// and EPD keep-alive. Required singleton. 30 bytes.  [config packet 0x04; required]  (30
/// wire bytes.)
public struct PowerOption: ODPackedStruct {
    public static let wireSize = 30
    public static let packetID: UInt8 = 0x04

    /// power source type.  [enum PowerMode]
    public var powerMode: UInt8
    /// battery capacity, 24-bit LE; 0 = unknown.  [unit mAh]
    public var batteryCapacityMah: [UInt8]
    /// nominal awake/advertising time before sleep (actual may be shorter).  [unit ms]
    public var sleepTimeoutMs: UInt16
    /// BLE transmit-power setting (platform-specific units).
    public var txPower: UInt8
    /// sleep-related flags (bitfield).  [bits SleepFlags]
    public var sleepFlags: UInt8
    /// ADC pin measuring battery voltage; 0xFF = none.  [default 0xFF]
    public var batterySensePin: UInt8
    /// pin enabling the battery-sense divider; 0xFF = none.  [default 0xFF]
    public var batterySenseEnablePin: UInt8
    /// battery-sense flags (bitfield).  [bits BatterySenseFlags]
    public var batterySenseFlags: UInt8
    /// battery chemistry model.  [enum CapacityEstimator]
    public var capacityEstimator: UInt8
    /// ADC voltage scaling / divider factor (implementation-specific).
    public var voltageScalingFactor: UInt16
    /// board deep-sleep current excl. MCU; 0 = unknown.  [unit uA]
    public var deepSleepCurrentUa: UInt32
    /// timer deep-sleep duration (ESP32 on battery); 0 = disabled.  [unit s]
    public var deepSleepTimeSeconds: UInt16
    /// BQ25616 charge-enable GPIO; 0 or 0xFF = unused.  [default 0xFF]
    public var chargeEnablePin: UInt8
    /// BQ25616 charge-state input GPIO; 0 or 0xFF = unused.  [default 0xFF]
    public var chargeStatePin: UInt8
    /// charger polarity flags (bitfield).  [bits ChargerFlags]
    public var chargerFlags: UInt8
    /// min awake window after first boot / button wake; 0 = default 120 s.  [unit s]
    public var minWakeTimeSeconds: UInt16
    /// EPD keep-alive: seconds the panel stays powered after a refresh before shutdown
    /// (values >30 clamped; 0 = power off immediately; forced 0 when an AXP2101 PMIC is
    /// present).  [unit s, min 0, max 30]
    public var screenTimeoutSeconds: UInt8
    /// future use; must be 0.  [reserved]
    public var reserved: [UInt8]

    public init(powerMode: UInt8 = 0, batteryCapacityMah: [UInt8] = [], sleepTimeoutMs: UInt16 = 0, txPower: UInt8 = 0, sleepFlags: UInt8 = 0, batterySensePin: UInt8 = 0, batterySenseEnablePin: UInt8 = 0, batterySenseFlags: UInt8 = 0, capacityEstimator: UInt8 = 0, voltageScalingFactor: UInt16 = 0, deepSleepCurrentUa: UInt32 = 0, deepSleepTimeSeconds: UInt16 = 0, chargeEnablePin: UInt8 = 0, chargeStatePin: UInt8 = 0, chargerFlags: UInt8 = 0, minWakeTimeSeconds: UInt16 = 0, screenTimeoutSeconds: UInt8 = 0, reserved: [UInt8] = []) {
        self.powerMode = powerMode
        self.batteryCapacityMah = batteryCapacityMah
        self.sleepTimeoutMs = sleepTimeoutMs
        self.txPower = txPower
        self.sleepFlags = sleepFlags
        self.batterySensePin = batterySensePin
        self.batterySenseEnablePin = batterySenseEnablePin
        self.batterySenseFlags = batterySenseFlags
        self.capacityEstimator = capacityEstimator
        self.voltageScalingFactor = voltageScalingFactor
        self.deepSleepCurrentUa = deepSleepCurrentUa
        self.deepSleepTimeSeconds = deepSleepTimeSeconds
        self.chargeEnablePin = chargeEnablePin
        self.chargeStatePin = chargeStatePin
        self.chargerFlags = chargerFlags
        self.minWakeTimeSeconds = minWakeTimeSeconds
        self.screenTimeoutSeconds = screenTimeoutSeconds
        self.reserved = reserved
    }

    public init?(bytes: [UInt8]) {
        guard bytes.count >= Self.wireSize else { return nil }
        self.powerMode = bytes[0]
        self.batteryCapacityMah = Array(bytes[1..<4])
        self.sleepTimeoutMs = odReadUInt16(bytes, 4, bigEndian: false)
        self.txPower = bytes[6]
        self.sleepFlags = bytes[7]
        self.batterySensePin = bytes[8]
        self.batterySenseEnablePin = bytes[9]
        self.batterySenseFlags = bytes[10]
        self.capacityEstimator = bytes[11]
        self.voltageScalingFactor = odReadUInt16(bytes, 12, bigEndian: false)
        self.deepSleepCurrentUa = odReadUInt32(bytes, 14, bigEndian: false)
        self.deepSleepTimeSeconds = odReadUInt16(bytes, 18, bigEndian: false)
        self.chargeEnablePin = bytes[20]
        self.chargeStatePin = bytes[21]
        self.chargerFlags = bytes[22]
        self.minWakeTimeSeconds = odReadUInt16(bytes, 23, bigEndian: false)
        self.screenTimeoutSeconds = bytes[25]
        self.reserved = Array(bytes[26..<30])
    }

    public func serialize() -> [UInt8] {
        var out = [UInt8]()
        out.reserveCapacity(Self.wireSize)
        out.append(powerMode)
        out.append(contentsOf: odFixedBytes(batteryCapacityMah, 3))
        odAppendUInt16(sleepTimeoutMs, &out, bigEndian: false)
        out.append(txPower)
        out.append(sleepFlags)
        out.append(batterySensePin)
        out.append(batterySenseEnablePin)
        out.append(batterySenseFlags)
        out.append(capacityEstimator)
        odAppendUInt16(voltageScalingFactor, &out, bigEndian: false)
        odAppendUInt32(deepSleepCurrentUa, &out, bigEndian: false)
        odAppendUInt16(deepSleepTimeSeconds, &out, bigEndian: false)
        out.append(chargeEnablePin)
        out.append(chargeStatePin)
        out.append(chargerFlags)
        odAppendUInt16(minWakeTimeSeconds, &out, bigEndian: false)
        out.append(screenTimeoutSeconds)
        out.append(contentsOf: odFixedBytes(reserved, 4))
        return out
    }
}

/// Per-panel configuration: geometry, controller, SPI pins, color scheme, and supported
/// transmission modes. Up to 4 instances. 46 bytes.  [config packet 0x20; repeatable (max
/// 4)]  (46 wire bytes.)
public struct DisplayConfig: ODPackedStruct {
    public static let wireSize = 46
    public static let packetID: UInt8 = 0x20

    /// 0-based display index (unique per display block).
    public var instanceNumber: UInt8
    /// panel technology.  [enum DisplayTechnology]
    public var displayTechnology: UInt8
    /// display controller / panel type.  [enum PanelIC]
    public var panelIcType: UInt16
    /// panel pixel width.  [unit px]
    public var pixelWidth: UInt16
    /// panel pixel height.  [unit px]
    public var pixelHeight: UInt16
    /// active area width.  [unit mm]
    public var activeWidthMm: UInt16
    /// active area height.  [unit mm]
    public var activeHeightMm: UInt16
    /// OEPL legacy tag type (optional; 0 if unused). Canonical snake_case of config.yaml
    /// legacy_tagtype / firmware tag_type.
    public var legacyTagType: UInt16
    /// physical rotation.  [enum Rotation]
    public var rotation: UInt8
    /// panel reset GPIO; 0xFF = none.  [default 0xFF]
    public var resetPin: UInt8
    /// panel busy-status GPIO; 0xFF = none.  [default 0xFF]
    public var busyPin: UInt8
    /// data/command select; doubles as SPI MISO on OpenDisplay-runtime IT8951 / Seeed ED103
    /// panels.
    public var dcPin: UInt8
    /// SPI chip-select; 0xFF = none.  [default 0xFF]
    public var csPin: UInt8
    /// data-out pin (SPI MOSI / data line).
    public var dataPin: UInt8
    /// partial-update capability.  [enum PartialUpdateSupport]
    public var partialUpdateSupport: UInt8
    /// color/plane scheme.  [enum ColorScheme]
    public var colorScheme: UInt8
    /// supported image/data transmission modes (bitfield).  [bits TransmissionModes]
    public var transmissionModes: UInt8
    /// SPI SCLK pin.
    public var clkPin: UInt8
    /// second CS for panels split over 2 drivers (dual-controller Spectra); 0xFF = none.
    /// Canonical name (firmware called it reserved_pin_2).  [default 0xFF, since 1.4]
    public var csPin2: UInt8
    /// spare pin; must be 0.  [reserved]
    public var reservedPin3: UInt8
    /// spare pin; must be 0.  [reserved]
    public var reservedPin4: UInt8
    /// spare pin; must be 0.  [reserved]
    public var reservedPin5: UInt8
    /// spare pin; must be 0.  [reserved]
    public var reservedPin6: UInt8
    /// spare pin; must be 0.  [reserved]
    public var reservedPin7: UInt8
    /// spare pin; must be 0.  [reserved]
    public var reservedPin8: UInt8
    /// energy consumed by a full refresh; 0 = unknown.  [unit mC]
    public var fullUpdateMc: UInt16
