    public var reqWindow: UInt8
    /// requested ACK cadence (frames per SACK).  [min 1, max 32]
    public var reqAckEvery: UInt8
    /// largest on-wire frame the client will send.
    public var clientMaxFrame: UInt16
    /// decompressed byte total to transfer (partial: plane_size x 2).
    public var totalSize: UInt32

    public init(version: UInt8 = 0, flags: UInt8 = 0, reqWindow: UInt8 = 0, reqAckEvery: UInt8 = 0, clientMaxFrame: UInt16 = 0, totalSize: UInt32 = 0) {
        self.version = version
        self.flags = flags
        self.reqWindow = reqWindow
        self.reqAckEvery = reqAckEvery
        self.clientMaxFrame = clientMaxFrame
        self.totalSize = totalSize
    }

    public init?(bytes: [UInt8]) {
        guard bytes.count >= Self.wireSize else { return nil }
        self.version = bytes[0]
        self.flags = bytes[1]
        self.reqWindow = bytes[2]
        self.reqAckEvery = bytes[3]
        self.clientMaxFrame = odReadUInt16(bytes, 4, bigEndian: false)
        self.totalSize = odReadUInt32(bytes, 6, bigEndian: false)
    }

    public func serialize() -> [UInt8] {
        var out = [UInt8]()
        out.reserveCapacity(Self.wireSize)
        out.append(version)
        out.append(flags)
        out.append(reqWindow)
        out.append(reqAckEvery)
        odAppendUInt16(clientMaxFrame, &out, bigEndian: false)
        odAppendUInt32(totalSize, &out, bigEndian: false)
        return out
    }
}

