        out.append(maxWindow)
        out.append(maxAckEvery)
        odAppendUInt16(maxFrame, &out, bigEndian: false)
        out.append(respFlags)
        return out
    }
}

/// 5-byte selective-ACK data in the PIPE 0x0081 ACK frame (device->host). highest_seen is
/// implicitly acked; ack_mask bit i (LSB first) acks chunk (highest_seen - 1 - i).
/// [payload of CMD_PIPE_WRITE_DATA]  (5 wire bytes.)
public struct PipeSack: ODPackedStruct {
    public static let wireSize = 5
    public static let message = "CMD_PIPE_WRITE_DATA"

    /// highest received seq (mod 256), implicitly acked.
    public var highestSeen: UInt8
    /// selective-ACK bitmask below highest_seen (bit i = seq highest_seen-1-i).
    public var ackMask: UInt32

    public init(highestSeen: UInt8 = 0, ackMask: UInt32 = 0) {
        self.highestSeen = highestSeen
        self.ackMask = ackMask
    }

    public init?(bytes: [UInt8]) {
        guard bytes.count >= Self.wireSize else { return nil }
        self.highestSeen = bytes[0]
        self.ackMask = odReadUInt32(bytes, 1, bigEndian: false)
    }

    public func serialize() -> [UInt8] {
        var out = [UInt8]()
        out.reserveCapacity(Self.wireSize)
        out.append(highestSeen)
        odAppendUInt32(ackMask, &out, bigEndian: false)
        return out
    }
}

/// 17-byte header for CMD_PARTIAL_WRITE_START 0x0076, following the 2 opcode bytes
/// (host->device). ENTIRELY BIG-ENDIAN -- the showcase for the per-message endianness
/// split: the PIPE 0x80 path carries the same geometry LITTLE-endian (see PipePartialExt).
/// x and width must be multiples of 8; old_etag must equal the currently displayed etag.
/// [payload of CMD_PARTIAL_WRITE_START]  (17 wire bytes.)
public struct PartialWriteStartHeader: ODPackedStruct {
    public static let wireSize = 17
    public static let message = "CMD_PARTIAL_WRITE_START"

    /// partial-write flags (see protocol.h 0x76 @request).
    public var flags: UInt8
    /// etag currently displayed; must match.  [BIG-ENDIAN]
    public var oldEtag: UInt32
    /// etag to store after this write.  [BIG-ENDIAN]
    public var newEtag: UInt32
    /// region left edge (multiple of 8).  [unit px, BIG-ENDIAN]
    public var x: UInt16
    /// region top edge.  [unit px, BIG-ENDIAN]
    public var y: UInt16
    /// region width (multiple of 8).  [unit px, BIG-ENDIAN]
    public var width: UInt16
    /// region height.  [unit px, BIG-ENDIAN]
    public var height: UInt16

    public init(flags: UInt8 = 0, oldEtag: UInt32 = 0, newEtag: UInt32 = 0, x: UInt16 = 0, y: UInt16 = 0, width: UInt16 = 0, height: UInt16 = 0) {
        self.flags = flags
        self.oldEtag = oldEtag
        self.newEtag = newEtag
        self.x = x
        self.y = y
        self.width = width
        self.height = height
    }

    public init?(bytes: [UInt8]) {
        guard bytes.count >= Self.wireSize else { return nil }
        self.flags = bytes[0]
        self.oldEtag = odReadUInt32(bytes, 1, bigEndian: true)
        self.newEtag = odReadUInt32(bytes, 5, bigEndian: true)
        self.x = odReadUInt16(bytes, 9, bigEndian: true)
        self.y = odReadUInt16(bytes, 11, bigEndian: true)
        self.width = odReadUInt16(bytes, 13, bigEndian: true)
        self.height = odReadUInt16(bytes, 15, bigEndian: true)
    }

    public func serialize() -> [UInt8] {
        var out = [UInt8]()
        out.reserveCapacity(Self.wireSize)
        out.append(flags)
        odAppendUInt32(oldEtag, &out, bigEndian: true)
        odAppendUInt32(newEtag, &out, bigEndian: true)
        odAppendUInt16(x, &out, bigEndian: true)
        odAppendUInt16(y, &out, bigEndian: true)
        odAppendUInt16(width, &out, bigEndian: true)
        odAppendUInt16(height, &out, bigEndian: true)
        return out
    }
}

/// 21-byte CMD_AUTHENTICATE 0x0050 step-1 response DATA (device->host), after the
/// [status][echo] framing: the device's nonce + id the client signs. This handshake is
/// ALWAYS plaintext (bootstraps the session).  [payload of CMD_AUTHENTICATE]  (21 wire
/// bytes.)
public struct AuthChallenge: ODPackedStruct {
    public static let wireSize = 21
    public static let message = "CMD_AUTHENTICATE"

    /// auth status = AUTH_STATUS_CHALLENGE (0x00) on success (see protocol.h).
    public var status: UInt8
    /// device nonce; part of the CMAC input.
    public var serverNonce: [UInt8]
    /// device id; part of the CMAC input.
    public var deviceId: UInt32

    public init(status: UInt8 = 0, serverNonce: [UInt8] = [], deviceId: UInt32 = 0) {
        self.status = status
        self.serverNonce = serverNonce
        self.deviceId = deviceId
    }

    public init?(bytes: [UInt8]) {
        guard bytes.count >= Self.wireSize else { return nil }
        self.status = bytes[0]
        self.serverNonce = Array(bytes[1..<17])
        self.deviceId = odReadUInt32(bytes, 17, bigEndian: false)
    }

    public func serialize() -> [UInt8] {
        var out = [UInt8]()
        out.reserveCapacity(Self.wireSize)
        out.append(status)
        out.append(contentsOf: odFixedBytes(serverNonce, 16))
        odAppendUInt32(deviceId, &out, bigEndian: false)
        return out
    }
}

/// 32-byte CMD_AUTHENTICATE 0x0050 step-2 request payload (host->device): the client nonce
/// and the AES-CMAC over (server_nonce || client_nonce || device_id).  [payload of
/// CMD_AUTHENTICATE]  (32 wire bytes.)
public struct AuthProof: ODPackedStruct {
    public static let wireSize = 32
    public static let message = "CMD_AUTHENTICATE"

    /// client nonce; part of the CMAC input.
    public var clientNonce: [UInt8]
    /// AES-CMAC(master_key, server_nonce || client_nonce || device_id).
    public var mac: [UInt8]

    public init(clientNonce: [UInt8] = [], mac: [UInt8] = []) {
        self.clientNonce = clientNonce
        self.mac = mac
    }

    public init?(bytes: [UInt8]) {
        guard bytes.count >= Self.wireSize else { return nil }
        self.clientNonce = Array(bytes[0..<16])
        self.mac = Array(bytes[16..<32])
    }

    public func serialize() -> [UInt8] {
        var out = [UInt8]()
        out.reserveCapacity(Self.wireSize)
        out.append(contentsOf: odFixedBytes(clientNonce, 16))
        out.append(contentsOf: odFixedBytes(mac, 16))
        return out
    }
}

/// 16-byte OpenDisplay manufacturer-specific data. Broadcast in BLE advertisements and
/// returned by CMD_READ_MSD 0x0044 (device->host). Battery voltage is 10 bits (10 mV
/// units): the low 8 bits are battery_voltage_low, the 9th bit is status bit0; the 10th is
/// implied 0 / reserved by firmware.  [payload of CMD_READ_MSD]  (16 wire bytes.)
public struct MsdAdvertisement: ODPackedStruct {
    public static let wireSize = 16
    public static let message = "CMD_READ_MSD"

    /// BLE company identifier.
    public var companyId: UInt16
    /// config-driven dynamic area: button/touch/SHT40/BQ27220 slots at indices set by the
    /// relevant config packets.
    public var dynamic: [UInt8]
    /// MCU chip temperature (signed degrees C, firmware-defined offset).  [unit C]
    public var chipTemperature: UInt8
    /// low 8 bits of the 10-bit battery voltage (10 mV units); high bit in status bit0.
    /// [unit 10mV]
    public var batteryVoltageLow: UInt8
    /// status flags + battery voltage MSB + main-loop counter nibble.  [bits MsdStatusBits]
    public var status: UInt8

    public init(companyId: UInt16 = 0, dynamic: [UInt8] = [], chipTemperature: UInt8 = 0, batteryVoltageLow: UInt8 = 0, status: UInt8 = 0) {
        self.companyId = companyId
        self.dynamic = dynamic
        self.chipTemperature = chipTemperature
        self.batteryVoltageLow = batteryVoltageLow
        self.status = status
    }

    public init?(bytes: [UInt8]) {
        guard bytes.count >= Self.wireSize else { return nil }
        self.companyId = odReadUInt16(bytes, 0, bigEndian: false)
        self.dynamic = Array(bytes[2..<13])
        self.chipTemperature = bytes[13]
        self.batteryVoltageLow = bytes[14]
        self.status = bytes[15]
    }

    public func serialize() -> [UInt8] {
        var out = [UInt8]()
        out.reserveCapacity(Self.wireSize)
        odAppendUInt16(companyId, &out, bigEndian: false)
        out.append(contentsOf: odFixedBytes(dynamic, 11))
        out.append(chipTemperature)
        out.append(batteryVoltageLow)
        out.append(status)
        return out
    }
}
